using System;
using System.Drawing;
using System.IO;

namespace ConvertidorImagenes
{
    /// <summary>
    /// Carga los iconos de la aplicación. Van incrustados como Base64 en el
    /// propio código (no dependen de ninguna carpeta externa ni de la
    /// configuración de 'Copiar en el directorio de salida'), así que
    /// siempre están disponibles sin importar dónde se ejecute el .exe.
    /// </summary>
    public static class IconLoader
    {
        // Caché para evitar decodificar la misma imagen Base64 más de una vez.
        private static readonly System.Collections.Generic.Dictionary<string, Image> _cache =
            new System.Collections.Generic.Dictionary<string, Image>();

        private static readonly System.Collections.Generic.Dictionary<string, string> _data =
            new System.Collections.Generic.Dictionary<string, string>
        {
            { "logo", "" },
            { "office", "" },
            { "ocr", "" },
            { "resize", "" },
            { "help", "" },
            { "home", "" },
            { "search", "" },
            { "bell", "" },
            { "clock", "" },
            { "star_filled", "" },
            { "star_outline", "" },
            { "bulb", "" },
            { "close", "" },
        };

        public static Image Load(string name)
        {
            try
            {
                // Devolver desde caché si ya se decodificó antes.
                if (_cache.TryGetValue(name, out Image cached))
                    return new Bitmap(cached);

                if (_data.TryGetValue(name, out string base64))
                {
                    byte[] bytes = Convert.FromBase64String(base64);
                    using (var ms = new MemoryStream(bytes))
                    using (var temp = Image.FromStream(ms))
                    {
                        var bmp = new Bitmap(temp);
                        _cache[name] = bmp;       // guardar en caché
                        return new Bitmap(bmp);    // devolver copia
                    }
                }
            }
            catch
            {
                // Si algo falla, seguimos sin romper la UI.
            }
            return null;
        }
    }
}